# dependency_sync.py — sync Jira ticket status to dependency registry

import requests
from dataclasses import dataclass
from typing import Dict, Optional

JIRA_BASE = "https://yourorg.atlassian.net"
REGISTRY_API = "https://registry.internal/api/dependencies"

@dataclass
class DependencyStatusMapping:
    registry_dep_id: str
    jira_ticket_id: str
    green_statuses: tuple = ("Done", "Closed")
    amber_statuses: tuple = ("Blocked", "In Review", "Waiting")
    red_statuses: tuple = ("Cancelled", "On Hold")

def fetch_jira_status(ticket_id: str, jira_token: str) -> Optional[str]:
    headers = {"Authorization": f"Bearer {jira_token}"}
    response = requests.get(
        f"{JIRA_BASE}/rest/api/3/issue/{ticket_id}",
        headers=headers, timeout=10
    )
    response.raise_for_status()
    return response.json()["fields"]["status"]["name"]

def map_to_registry_status(jira_status: str, mapping: DependencyStatusMapping) -> str:
    if jira_status in mapping.green_statuses:
        return "resolved"
    elif jira_status in mapping.red_statuses:
        return "red"
    elif jira_status in mapping.amber_statuses:
        return "amber"
    return "green"

def sync_dependency_statuses(
    mappings: list[DependencyStatusMapping],
    jira_token: str,
    registry_token: str
) -> Dict[str, str]:
    results = {}
    for mapping in mappings:
        try:
            jira_status = fetch_jira_status(mapping.jira_ticket_id, jira_token)
            registry_status = map_to_registry_status(jira_status, mapping)
            # POST update to registry
            requests.patch(
                f"{REGISTRY_API}/{mapping.registry_dep_id}",
                json={"status": registry_status, "source": "jira-sync"},
                headers={"Authorization": f"Bearer {registry_token}"},
                timeout=10
            )
            results[mapping.registry_dep_id] = registry_status
        except Exception as e:
            results[mapping.registry_dep_id] = f"error: {e}"
    return results
